# Base shapes module - defines abstract base class, interface, and enum

interface IDrawable:
    def draw(self) -> str: ...

enum Color:
    RED = 1
    GREEN = 2
    BLUE = 3

@abstract
class Shape:
    name: str
    color: Color

    def __init__(self, name: str, color: Color):
        self.name = name
        self.color = color

    @virtual
    def area(self) -> float:
        return 0.0

    @virtual
    def describe(self) -> str:
        return f"Shape({self.name})"

    def get_color_name(self) -> str:
        return self.color.name

