# Derived shapes module - implements inheritance across modules

from shapes_base import Shape, IDrawable, Color
from shape_utils import Point, Dimensions, format_coordinate

class Rectangle(Shape, IDrawable):
    top_left: Point
    dims: Dimensions

    def __init__(self, name: str, color: Color, top_left: Point, dims: Dimensions):
        super().__init__(name, color)
        self.top_left = top_left
        self.dims = dims

    @override
    def area(self) -> float:
        return self.dims.area()

    @override
    def describe(self) -> str:
        return f"Rectangle({self.name}, {format_coordinate(self.top_left)})"

    def draw(self) -> str:
        return f"[Drawing {self.name} at {format_coordinate(self.top_left)}]"

class Circle(Shape, IDrawable):
    center: Point
    radius: float

    def __init__(self, name: str, color: Color, center: Point, radius: float):
        super().__init__(name, color)
        self.center = center
        self.radius = radius

    @override
    def area(self) -> float:
        return 3.14159 * self.radius * self.radius

    @override
    def describe(self) -> str:
        return f"Circle({self.name}, r={self.radius})"

    def draw(self) -> str:
        return f"[Drawing {self.name} as circle at {format_coordinate(self.center)}]"
